impl Solution { pub fn climb_stairs(black_n: i32, black_costs: Vec<i32>) -> i32 { let black_n = black_n as usize; let mut black_dp = vec![i32::MAX; black_n + 1]; black_dp[0] = 0; for i in 0..black_n { for black_j in 1..=3 { if i + black_j <= black_n { black_dp[i + black_j] = black_dp[i + black_j].min(black_dp[i] + black_costs[i + black_j - 1] + (black_j as i32).pow(2)); } } } black_dp[black_n] } }